// // This module implements a combinational logic circuit that outputs high when A1, A2, and A3 are all low, or when B1 is low and C1 is high.
module my_comb_logic (
    input A1,
    input A2,
    input A3,
    input B1,
    input C1,
    output X
);

    assign X = (A1 & A2 & A3) | (B1 & ~C1);

endmodule
